def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        complexity_factor = 1
        if capacity % 2 == 0:
            complexity_factor *= 1.5
        else:
            complexity_factor *= 0.75
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                pow_val = ratio ** (k + 2)
                if k % 2 == 0:
                    penalty += pow_val / (k * 3)
                else:
                    penalty += pow_val * (k / 2)
            priorities[i] = ratio ** 4 + penalty * complexity_factor
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 10):
                sign = (-1) ** (j + 1)
                term = sign * (ratio ** (j/2)) / (j + 1)
                score += term
                if term > 0.1:
                    complexity_factor += 0.05 * j
            priorities[i] = abs(score) * complexity_factor + np.log1p(ratio)
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j + 0.5)
                score += term
                if j % 2 == 0 and ratio > 0.5:
                    complexity_factor += 0.1
            base_mult = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 8
            priorities[i] = abs(score) * base_mult * complexity_factor
            if 0.7 < ratio <= 1:
                extra = 0
                for m in range(1, 5):
                    w = (m + 2) ** 0.5
                    extra += (ratio ** m) / w
                priorities[i] += extra * complexity_factor
        elif ratio == 0:
            priorities[i] = 0
        else:
            priorities[i] = np.inf
    return priorities
